    const MOD = 1000000000 + 7;
    const MAX_VAL = 5000;

    /**
     * Calculates the digit sum of a number.
     * @param {number} n
     * @returns {number}
     */
    const getDigitSum = (n) => {
        let sum = 0;
        n = Math.abs(n);
        while (n > 0) {
            sum += n % 10;
            n = Math.floor(n / 10);
        }
        return sum;
    };

    /**
     * Precomputes all numbers <= 5000 that have a specific digit sum.
     * Map: digitSum -> list of numbers
     * @returns {Map<number, number[]>}
     */
    const precomputeNumbers = () => {
        const numbersByDS = new Map();
        for (let i = 0; i <= MAX_VAL; i++) {
            const ds = getDigitSum(i);
            if (!numbersByDS.has(ds)) {
                numbersByDS.set(ds, []);
            }
            numbersByDS.get(ds).push(i);
        }
        return numbersByDS;
    };

    const numbersByDS = precomputeNumbers();

    /**
     * Step 1: Check for immediate impossibilities based on digitSum constraints.
     * Filter numbers for each required digitSum.
     * @returns {number[][] | null} An array where element i is the sorted list of valid numbers for digitSum[i], or null if any is empty.
     */
    const getValidNumberLists = () => {
        const lists = [];
        for (let i = 0; i < digitSum.length; i++) {
            const requiredDS = digitSum[i];
            const candidates = numbersByDS.get(requiredDS);

            if (!candidates || candidates.length === 0) {
                return null; // Impossible
            }
            // Ensure the list is sorted as we need to maintain non-decreasing order
            candidates.sort((a, b) => a - b);
            lists.push(candidates);
        }
        return lists;
