    if (validLists === null) {
        return 0;
    }

    const N = digitSum.length;
    const lists = validLists;

    // DP state: dp[i][j] = number of valid arrays of length i+1 ending with a number whose value is lists[i][j].
    // The index j refers to the index within lists[i].
    // Since we need to calculate the count based on the *value* of the previous element, 
    // a simpler DP approach is possible:
    // dp[i][j] = number of valid prefixes of length i+1, where the (i+1)-th element is lists[i][j].

    // Initialize DP table: dp[i] will store the counts for index i of digitSum.
    // dp[i] is an array where dp[i][j] is the count.
    const dp = Array(N).fill(0).map(() => []);

    // Base Case: i = 0
    // For the first element, any valid number is a valid prefix of length 1.
    dp[0] = Array(lists[0].length).fill(1);

    // Transitions: i > 0
    for (let i = 1; i < N; i++) {
        const currentList = lists[i];
        const prevList = lists[i - 1];
        dp[i] = Array(currentList.length).fill(0);

        for (let j = 0; j < currentList.length; j++) {
            const currentVal = currentList[j];
            let count = 0;

            // We need to sum up dp[i-1][k] for all k such that prevList[k] <= currentVal.
            // Since both prevList and currentList are sorted, we can optimize this.

            // Find the maximum index k in prevList such that prevList[k] <= currentVal.
            // This is equivalent to finding the count of elements in prevList that are <= currentVal.

            let sumPrevCounts = 0;
            for (let k = 0; k < prevList.length; k++) {
                if (prevList[k] <= currentVal) {
                    // Add the count for prefixes ending in prevList[k]
                    sumPrevCounts = (sumPrevCounts + dp[i - 1][k]) % MOD;
                } else {
                    // Since prevList is sorted, we can break early
                    break;
                }
            }

            dp[i][j] = sumPrevCounts;
        }
    }

    // Final Result: Sum up all counts in the last DP array.
    let totalCount = 0;
    if (N > 0) {
        for (let j = 0; j < dp[N - 1].length; j++) {
            totalCount = (totalCount + dp[N - 1][j]) % MOD;
        }
    }

    return totalCount;
