import scala.collection.mutable

object Solution {
  def digitSum(digitSum: Array[Long]): Long = {
    val MOD: Long = 1_000_000_007L
    val MAX_VAL: Int = 5000

    def getDigitSum(n: Int): Int = {
      var sum = 0
      var num = Math.abs(n)
      while (num > 0) {
        sum += num % 10
        num /= 10
      }
      sum
    }

    // Precompute all numbers <= 5000 that have a specific digit sum.
    // Map: digitSum -> list of numbers
    val numbersByDS: mutable.Map[Int, mutable.List[Int]] = mutable.Map()
    for (i <- 0 to MAX_VAL) {
      val ds = getDigitSum(i)
      numbersByDS.putIfAbsent(ds, mutable.List())
      numbersByDS(ds).append(i)
    }

    // Get sorted lists of valid numbers for each required digitSum.
    val lists: mutable.Array[mutable.List[Int]] = mutable.Array(digitSum.length)
    for (i <- 0 until digitSum.length) {
      val requiredDS = digitSum(i).toInt
      val candidates = numbersByDS.get(requiredDS)

      if (candidates == null || candidates.isEmpty) {
        return 0L // Impossible
      }

      // Ensure the list is sorted (though precomputation should yield sorted lists if iterating 0 to MAX_VAL)
      val sortedCandidates = candidates.sortBy(x => x).toSeq
      lists(i) = mutable.List(sortedCandidates: _*)
    }

    val N = digitSum.length

    // DP state: dp[i] is an array where dp[i](j) is the count of valid prefixes of length i+1, 
    // where the (i+1)-th element is lists(i)(j).
    // We use mutable arrays/lists for efficiency in updates.
    val dp: Array[mutable.List[Long]] = Array.fill(N)(mutable.List())

    // Base Case: i = 0
    // For the first element, any valid number is a valid prefix of length 1.
    val firstList = lists(0)
    val dp0 = mutable.List.fill(firstList.size)(1L)
    dp(0) = dp0

    // Transitions: i > 0
    for (i <- 1 until N) {
      val currentList = lists(i)
      val prevList = lists(i - 1)
      val dp_i = mutable.List.fill(currentList.size)(0L)

      for (j <- 0 until currentList.size) {
        val currentVal = currentList(j)
        var sumPrevCounts: Long = 0

        // Find the sum of dp[i-1][k] for all k such that prevList[k] <= currentVal.
        for (k <- 0 until prevList.size) {
          val prevVal = prevList(k)
          if (prevVal <= currentVal) {
            // Add the count for prefixes ending in prevList[k]
            sumPrevCounts = (sumPrevCounts + dp(i - 1)(k)) % MOD
          } else {
            // Since prevList is sorted, we can break early
            break
          }
        }

        dp_i(j) = sumPrevCounts
      }
      dp(i) = dp_i
    }

    // Final Result: Sum up all counts in the last DP array.
    var totalCount: Long = 0L
    if (N > 0) {
      val lastDP = dp(N - 1)
      for (count <- lastDP) {
        totalCount = (totalCount + count) % MOD
      }
    }

    totalCount
  }
}
